namespace sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Models;

public record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    List<StatusUpdate> StatusUpdates);

public record StatusUpdate(
    string Description,
    DateTimeOffset Timestamp);

using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Models;

namespace sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Models;
using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Services;

namespace sv_1c5d1afbd0494cd88f19c85e462d8960.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Departed facility – New York, NY", new DateTimeOffset(2026, 5, 23, 6, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at hub – Chicago, IL", new DateTimeOffset(2026, 5, 24, 14, 15, 0, TimeSpan.Zero)),
            ]),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit – Denver, CO", new DateTimeOffset(2026, 5, 18, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for delivery", new DateTimeOffset(2026, 5, 20, 7, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered – Left at front door", new DateTimeOffset(2026, 5, 20, 11, 32, 0, TimeSpan.Zero)),
            ]),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Warehouse – Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Order confirmed", new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Preparing shipment", new DateTimeOffset(2026, 5, 25, 10, 30, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate a slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Models;

namespace sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API.
/// Used when the component runs in WebAssembly.
/// </summary>
public class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Models
@using sv_1c5d1afbd0494cd88f19c85e462d8960.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> — @update.Description
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; stop silently
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

