            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Departed facility – New York, NY", new DateTimeOffset(2026, 5, 23, 6, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at hub – Chicago, IL", new DateTimeOffset(2026, 5, 24, 14, 15, 0, TimeSpan.Zero)),
            ]),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit – Denver, CO", new DateTimeOffset(2026, 5, 18, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for delivery", new DateTimeOffset(2026, 5, 20, 7, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered – Left at front door", new DateTimeOffset(2026, 5, 20, 11, 32, 0, TimeSpan.Zero)),
            ]),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Warehouse – Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Order confirmed", new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Preparing shipment", new DateTimeOffset(2026, 5, 25, 10, 30, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate a slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

